import sys
import ast

# Path to the file under test
SOURCE_FILE = "/src/dsvw.py"

def is_dynamic_urllib_usage(node):
    """
    Detect patterns where urllib (or urllib.request) functions are called
    with arguments that originate from user-controlled data (e.g., request
    parameters extracted from the URL query string).
    """
    # Look for calls like urllib.request.urlopen(...), urllib.urlopen(...), urllib.parse.urljoin(...)
    if isinstance(node, ast.Call) and isinstance(node.func, ast.Attribute):
        # Resolve full name: urllib.*, urllib.request.*
        if isinstance(node.func.value, ast.Name) and node.func.value.id == "urllib":
            func_name = f"urllib.{node.func.attr}"
        elif (isinstance(node.func.value, ast.Attribute) and
              isinstance(node.func.value.value, ast.Name) and
              node.func.value.value.id == "urllib" and
              node.func.value.attr == "request"):
            func_name = f"urllib.request.{node.func.attr}"
        else:
            return False

        # Check if any argument is a Name that could be user‑controlled
        for arg in node.args:
            if isinstance(arg, ast.Name):
                # Heuristic: names that appear in the `params` dict or derived from query parsing
                if arg.id in {"url", "target", "path", "resource"} or "param" in arg.id.lower():
                    return True
            # Direct concatenation with a Name (e.g., "http://" + user_input)
            if isinstance(arg, ast.BinOp) and isinstance(arg.op, ast.Add):
                left, right = arg.left, arg.right
                if any(isinstance(side, ast.Name) for side in (left, right)):
                    return True
        # Keyword arguments
        for kw in node.keywords:
            if isinstance(kw.value, ast.Name):
                if kw.value.id in {"url", "target", "path", "resource"} or "param" in kw.value.id.lower():
                    return True
    return False

def analyze():
    try:
        with open(SOURCE_FILE, "r", encoding="utf-8") as f:
            tree = ast.parse(f.read(), filename=SOURCE_FILE)
    except Exception:
        sys.exit(1)

    # Walk the AST looking for suspicious urllib usage
    for node in ast.walk(tree):
        if is_dynamic_urllib_usage(node):
            print("VALIDATION_SUCCESS: Detected dynamic urllib usage that may be unsafe.")
            sys.exit(0)

    # No problematic pattern found
    sys.exit(1)

if __name__ == "__main__":
    analyze()

import sys
import re
from pathlib import Path

TARGET_FILE = "/src/dsvw.py"

def is_vulnerable(content: str) -> bool:
    # Detect subprocess.run or subprocess.Popen with shell=True
    dangerous_call = re.search(r"subprocess\.(run|Popen)\s*\([^)]*shell\s*=\s*True", content)
    if not dangerous_call:
        return False

    # Ensure no basic sanitization (shlex.quote, shlex.split, or list args) is used
    has_sanitizer = re.search(r"shlex\.quote|shlex\.split|\b\w+\s*=\s*\[", content)
    return not has_sanitizer

def main():
    try:
        code = Path(TARGET_FILE).read_text()
    except Exception:
        sys.exit(1)

    if is_vulnerable(code):
        print("VALIDATION_SUCCESS: dangerous subprocess usage detected")
        sys.exit(0)
    else:
        print("VALIDATION_FAILURE: no vulnerable pattern found")
        sys.exit(1)

if __name__ == "__main__":
    main()
